import React, { useState, useEffect, FunctionComponent, PropsWithChildren } from 'react';
import {
  getCalibrationEstimatesPagePath,
  getMainPagePath,
  getNoticesPagePath,
  getManagersPagePath,
} from '../app-path';
import { CallabtSDK } from 'callabt-sdk';
import { readAccessToken, storeAccessToken, deleteAccessToken } from '../local-storage';
import { navigate } from "gatsby";
import PageLayout from '../../view/component/page-layout/PageLayout';
import SignInPageContainer from '../SignInPageContainer';
import LoadingBackdrop from '../../view/component/backdrop/LoadingBackdrop';

const drawerListItems = [
  {
    text: '교정 견적 요청',
    icon: 'mail' as const,
    linkUrl: getCalibrationEstimatesPagePath(),
  },
  {
    text: '공지사항',
    icon: 'notice' as const,
    linkUrl: getNoticesPagePath(),
  },
  {
    text: '매니저',
    icon: 'face' as const,
    linkUrl: getManagersPagePath(),
  },
];

interface Props {
}

const PageWrapper: FunctionComponent<PropsWithChildren<Props>> = ({ children }) => {
  const [isDrawerOpened, setIsDrawerOpened] = useState(false);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [isInitializedAppData, setIsInitializedAppData] = useState(false);
  const [isInitializingAppData, setIsInitializingAppData] = useState(true);
  const [managerName, setManagerName] = useState('');

  const initializeAppData = async () => {
    setIsInitializingAppData(true);
    setIsInitializedAppData(false);
  
    const token = readAccessToken();

    if (token) {
      try {
        const {
          manager,
        } = await CallabtSDK.getCurrentManager({ accessToken: token });
        setAccessToken(token);
        setManagerName(manager.name);
      } catch (error) {
        deleteAccessToken();
        console.error(error);
      }
    }

    setIsInitializingAppData(false);
    setIsInitializedAppData(true);
  };

  useEffect(() => {
    initializeAppData();
  }, []);

  if (isInitializingAppData) {
    return (
      <LoadingBackdrop isShown={isInitializingAppData}/>
    );
  }

  const onSignedIn = async ({ accessToken: token }: { accessToken: string }) => {
    storeAccessToken(token);
    initializeAppData();
  };

  const onClickSignOut = () => {
    deleteAccessToken();
    setManagerName('');
    setAccessToken(null);
  };

  const onClickHome = () => {
    navigate(getMainPagePath());
    setIsDrawerOpened(false);
  }

  if (!isInitializedAppData || accessToken === null) {
    return (
      <SignInPageContainer
        onSignedIn={onSignedIn}
      />
    )
  }

  const onClickDrawerListItem = (index: number) => {
    const url = drawerListItems[index].linkUrl;
    navigate(url);
    setIsDrawerOpened(false);
  };

  return (
    <PageLayout
      isDrawerOpened={isDrawerOpened}
      onCloseDrawer={() => setIsDrawerOpened(false)}
      onClickMenuButton={() => setIsDrawerOpened(!isDrawerOpened)}
      drawerListItems={drawerListItems}
      managerName={managerName}
      onClickSignOut={onClickSignOut}
      onClickDrawerListItem={onClickDrawerListItem}
      onClickHome={onClickHome}
    >
      {children}
    </PageLayout>
  );
};

export default PageWrapper;
