import { CallabtSDK } from 'callabt-sdk';
import React, { FunctionComponent, useState } from 'react';

import SignInPage from '../../view/component/page/SignInPage';

interface Props {
  onSignedIn: (props: { accessToken: string }) => void;
}

const SignInPageContainer: FunctionComponent<Props> = ({
  onSignedIn,
}) => {
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [isSigningIn, setIsSigningIn] = useState(false);

  const onClickSignIn = async () => {
    if (!isSigningIn) {
      if (name.length === 0) {
        alert('이름을 입력해 주세요');
        return;
      }
  
      if (password.length < 8) {
        alert('비밀번호를 8자리 이상 입력해주세요.');
      }
  
      setIsSigningIn(true);
      try {
        const { accessToken } = await CallabtSDK.createManagerToken({ name, password });

        onSignedIn({ accessToken });
      } catch(error) {
        console.error(error);
        alert('로그인에 실패했습니다.')
      }
      setIsSigningIn(false);
    }
  };

  return (
    <SignInPage
      name={name}
      onChangeName={setName}
      password={password}
      onChangePassword={setPassword}
      onClickSignIn={onClickSignIn}
      isSigningIn={isSigningIn}
    />
  );
};

export default SignInPageContainer;
